@app.route('/sso')
def sso():
    req = request.args.copy()
    auth = OneLogin_Saml2_Auth(req, custom_base_path='/path/to/saml', settings=saml_settings)
    return redirect(auth.login())

@app.route('/acs')
def acs():
    req = request.form.copy()
    auth = OneLogin_Saml2_Auth(req, custom_base_path='/path/to/saml', settings=saml_settings)
    auth.process_response()
    errors = auth.get_errors()
    if not errors:
        user_info = auth.get_attributes()
